1	import { describe, it, expect } from "vitest";
2	import { runScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // --- Edge cases / simplest ---
6	  it("empty item list → premium 5 G (only the processing fee)", () => {
7	    const result = runScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result).toEqual({ results: [{ premium: 5 }] });
12	  });
13	
14	  // --- Base premiums for single main items (each base + 5 G fee) ---
15	  it.todo("single plain sword → premium 105 G (100 base + 5 fee)");
16	  it.todo("single plain amulet → premium 65 G (60 base + 5 fee)");
17	  it.todo("single plain staff → premium 85 G (80 base + 5 fee)");
18	  it.todo("single plain potion → premium 45 G (40 base + 5 fee)");
19	
20	  // --- Components (runes, moonstones) ---
21	  it.todo("single rune → premium 30 G (25 base + 5 fee)");
22	  it.todo("2 runes → premium 55 G (50 base + 5 fee)");
23	  it.todo("3 runes → premium 65 G (60 base block premium + 5 fee)");
24	  it.todo("4 runes → premium 105 G (100 base, no block + 5 fee)");
25	  it.todo("7 runes → premium 180 G (175 base + 5 fee)");
26	
27	  // --- 'Alike' components clarification ---
28	  it.todo("2 runes + 1 moonstone → premium 80 G (75 base, no block: different types + 5 fee)");
29	  it.todo("3 runes + 3 moonstones → premium 125 G (120 base = two separate blocks + 5 fee)");
30	
31	  // --- Premium modifiers (item-specific) ---
32	  it.todo("cursed sword → premium 155 G (100 + 50 curse + 5 fee)");
33	  it.todo("sword enchantment 5 → premium 135 G (100 + 30 high-ench + 5 fee)");
34	  it.todo("sword enchantment 4 → premium 105 G (no high-ench surcharge)");
35	  it.todo("cursed sword enchantment 5 → premium 185 G (100 + 50 + 30 + 5 fee)");
36	
37	  // --- Loyalty discount (policy-wide) ---
38	  it.todo("customer 2 years, plain sword → loyalty discount applies → premium 85 G (100 - 20 + 5)");
39	  it.todo("customer 1 year, plain sword → no loyalty discount → premium 105 G");
40	
41	  // --- First insurance vs. follow-up contract (policy-wide) ---
42	  it.todo("first quote, plain sword → +10 G initial assessment → premium 115 G (100 + 10 + 5)");
43	  it.todo("second quote (follow-up), plain sword → -15 G follow-up discount → premium 90 G (100 + 10 - 15 + 5)");
44	
45	  // --- Modifier scope on multi-item policy ---
46	  it.todo("cursed sword + plain amulet → premium 215 G (100 + 60 + 50 curse + 10 first + 5 fee)");
47	
48	  // --- Rounding (in MHPCO favor) ---
49	  it.todo("premium calc yielding 197.5 G → final 198 G (round up for premiums)");
50	  it.todo("payout calc yielding 350.5 G → final 350 G (round down for payouts)");
51	
52	  // --- Integration examples ---
53	  it.todo("newcomer with cursed sword → premium 165 G (100 + 50 + 10 = 160 + 5)");
54	  it.todo("long-standing customer's second contract, cursed sword ench 7 → premium 160 G");
55	
56	  // --- Claim: standard reimbursement (no special clauses) ---
57	  it.todo("regular steel sword ench 3, damage 500 → payout 400 (500 - 100 deductible)");
58	  it.todo("rune damaged, damage 200 → payout 100 (200 - 100 deductible, no special clause)");
59	
60	  // --- Claim: special clauses ---
61	  it.todo("dragon-material sword ench 8, damage 1000 → payout 400 (high-ench 50% then deductible)");
62	  it.todo("dragon-material sword ench 9, damage 1000 → payout 400 (50% wins, then deductible)");
63	  it.todo("dragon-material sword ench 5, damage 800 → payout 700 (dragon full, then deductible)");
64	  it.todo("steel sword ench 9, damage 1000 → payout 400 (high-ench 50%, then deductible)");
65	
66	  // --- Claim: deductible per damage event ---
67	  it.todo("dragon damages sword 500 and amulet 300 → payout 600 (deductible per item)");
68	
69	  // --- Claim: multiple items of same type ---
70	  it.todo("policy with two swords → insurance sum 2000, cap 4000");
71	  it.todo("policy with two swords, damages contains two sword entries → each has its own deductible");
72	  it.todo("policy with one sword, damages contains two sword entries → CLI exits non-zero (rejected)");
73	
74	  // --- Claim: cap exhaustion ---
75	  it.todo("sword + amulet → insurance sum 1600, cap 3200");
76	  it.todo("cursed sword (premium 165) → cap 2000 (based on unmodified insurance value)");
77	  it.todo("sword + 3 runes block → insurance sum 1750 (block discount doesn't reduce sum)");
78	  it.todo("sword cap 2000, two claims of 1500 each → first payout 1400 cap remaining 600; second payout 600 cap remaining 0");
79	
80	  // --- Edge cases: errors ---
81	  it.todo("quote with unknown item type → CLI exits non-zero, error to stderr");
82	  it.todo("claim references damage entry whose item not in policy → CLI exits non-zero");
83	  it.todo("claim with damage amount -200 → CLI exits non-zero");
84	});
